check("deformed spline chains weld compatible pieces and keep UV phase continuous", () => {
  const data = createFlatLandscapeData("small");
  data.splines = [{
    id: "road-chain",
    points: [
      { id: "a", position: [0, 0, 0], width: 2, falloff: 1 },
      { id: "b", position: [0, 0, 10], width: 2, falloff: 1 },
      { id: "c", position: [10, 0, 10], width: 2, falloff: 1 },
    ],
    segments: [
      { id: "s0", startPointId: "a", endPointId: "b", mesh: { enabled: true, assetId: "road", deform: true } },
      { id: "s1", startPointId: "b", endPointId: "c", mesh: { enabled: true, assetId: "road", deform: true } },
    ],
  }];
  const gltf = { scene: new Mesh(new BoxGeometry(2, 0.2, 10, 2, 1, 8)) } as unknown as GLTF;
  const built = buildLandscapeSplineMeshGroup({
    data,
    models: new Map([["road", gltf]]),
    castShadow: false,
    receiveShadow: true,
  });
  assert.ok(built);
  const group = built.group.children.find((child) => child.name === "deformed-road")!;
  assert.equal(group.children.length, 1, "one primitive over a chain should become one draw mesh");
  const mesh = group.children[0] as Mesh;
  const uv = mesh.geometry.getAttribute("uv");
  const u = Array.from({ length: uv.count }, (_, index) => uv.getX(index));
  const v = Array.from({ length: uv.count }, (_, index) => uv.getY(index));
  assert.ok(Math.min(...u) <= 0.001 || Math.min(...v) <= 0.001);
  assert.ok(Math.max(...u) >= 1.999 || Math.max(...v) >= 1.999, "the second piece must continue rather than restart its longitudinal UV");
  assert.ok(mesh.geometry.getAttribute("normal"), "normals are generated after welding");
});

// SM_Asphalt.glb is a small deterministic weld fixture (77 unique verts, 7 per
// end ring). It was retired from public content in favor of SM_Road_Asphalt.glb
// but kept here under tools/fixtures/ so this weld-topology test stays stable.
const asphaltGltfDocument = await new NodeIO().registerExtensions([KHRMaterialsSpecular]).readBinary(
  new Uint8Array(readFileSync("tools/fixtures/SM_Asphalt.glb")),
);

check("SM_Asphalt chain welds every shared end-ring vertex", () => {
  const sourceNode = asphaltGltfDocument.getRoot().listNodes().find((node) => node.getMesh());
  const primitive = sourceNode?.getMesh()?.listPrimitives()[0];
  const sourcePositions = primitive?.getAttribute("POSITION");
  const sourceUv = primitive?.getAttribute("TEXCOORD_0");
  const sourceIndices = primitive?.getIndices();
  assert.ok(sourceNode && sourcePositions && sourceUv && sourceIndices);
  const geometry = new BufferGeometry();
  geometry.setAttribute("position", new Float32BufferAttribute(sourcePositions.getArray()!.slice(), 3));
  geometry.setAttribute("uv", new Float32BufferAttribute(sourceUv.getArray()!.slice(), 2));
  geometry.setIndex(Array.from(sourceIndices.getArray()!));
  const root = new Group();
  const sourceMesh = new Mesh(geometry, new MeshBasicMaterial());
  sourceMesh.matrix.copy(new Matrix4().fromArray(sourceNode.getMatrix()));
  sourceMesh.matrixAutoUpdate = false;
  root.add(sourceMesh);
  root.updateMatrixWorld(true);

  const data = createFlatLandscapeData("small");
  data.splines = [{
    id: "asphalt-chain",
    points: [
      { id: "a", position: [0, 0, 0], width: 7, falloff: 0 },
      { id: "b", position: [0, 0, 14], width: 7, falloff: 0 },
      { id: "c", position: [14, 0, 14], width: 7, falloff: 0 },
    ],
    segments: [
      { id: "s0", startPointId: "a", endPointId: "b", mesh: { enabled: true, assetId: "asphalt", deform: true } },
      { id: "s1", startPointId: "b", endPointId: "c", mesh: { enabled: true, assetId: "asphalt", deform: true } },
    ],
  }];
  const built = buildLandscapeSplineMeshGroup({
    data,
    models: new Map([["asphalt", { scene: root } as unknown as GLTF]]),
    castShadow: false,
    receiveShadow: true,
  });
  assert.ok(built);
  const group = built.group.children.find((child) => child.name === "deformed-asphalt")!;
  const welded = (group.children[0] as Mesh).geometry.getAttribute("position");
  // The GLB has 77 unique vertices and seven vertices across each end ring.
  // Two pieces therefore become 77 + 77 - 7, rather than remaining separate.
  assert.equal(welded.count, 147);
});

// colliderBoxFromBounds bakes placement scale into the world-aligned size; for
// an origin-centered model the center offset stays zero.
check("colliderBoxFromBounds bakes scale into a centered model's footprint", () => {
  const box = colliderBoxFromBounds(
    new Box3(new Vector3(-1, -1, -1), new Vector3(1, 1, 1)),
    { position: [10, 0, 0], scale: [3, 1, 2] },
  );
  assert.deepEqual(box.size, [6, 2, 4]);
  assert.deepEqual(box.center, [0, 0, 0]);
});

// Rotation intentionally does not resize the collider footprint. A rotated wall
// keeps the same collision dimensions; an off-origin model still yields a center
// offset relative to its placement position.
check("colliderBoxFromBounds ignores rotation while preserving scale and offset", () => {
  const box = colliderBoxFromBounds(
    new Box3(new Vector3(-1, 0, -0.25), new Vector3(1, 2, 0.25)),
    { position: [5, 0, 0], rotationYDeg: 90 },
  );
  assert.deepEqual(box.size, [2, 2, 0.5]);
  // The box spans y [0,2] about position y=0, so its center sits 1 unit up.
  assert.deepEqual(box.center, [0, 1, 0]);
});

// The editor "Show > Collision" overlay derives one world box per collidable
// placement/character: `collision: false` opts out, the sensor flag carries
// through, and each box is the model's bounds under its placement transform.
check("collisionWireboxes: one box per collider, skips collision:false, flags sensors", () => {
  const layout: RoomLayout = {
    schema: 1,
    name: "collision-overlay-fixture",
    loadGroups: [],
    instances: [
      {
        assetId: "wall",
        placements: [
          { position: [0, 0, 0], scale: [2, 1, 1] },
          { position: [5, 0, 0], collision: false }, // opted out -> no box
        ],
      },
      { assetId: "zone", placements: [{ position: [0, 0, -3], sensor: true }] },
    ],
    characters: [{ assetId: "hero", position: [1, 0, 0] }],
    lights: [],
  };
  const unit = () => new Box3(new Vector3(-0.5, -0.5, -0.5), new Vector3(0.5, 0.5, 0.5));
  const localBounds = new Map([
    ["wall", unit()],
    ["zone", unit()],
    ["hero", unit()],
  ]);

  const boxes = collisionWireboxes(layout, localBounds);
  assert.equal(boxes.length, 3); // wall[0] + zone + hero; wall[1] opted out

  // wall[0]: unit bounds scaled x2 on X about origin -> x span [-1,1].
  const wall = boxes[0]!;
  assert.equal(wall.sensor, false);
  assert.deepEqual(wall.box.min.toArray(), [-1, -0.5, -0.5]);
  assert.deepEqual(wall.box.max.toArray(), [1, 0.5, 0.5]);

  // zone is a sensor centered at z=-3.
  const zone = boxes[1]!;
  assert.equal(zone.sensor, true);
  assert.deepEqual(zone.box.min.toArray(), [-0.5, -0.5, -3.5]);

  // hero (character) is collidable by default, centered at x=1.
  const hero = boxes[2]!;
  assert.equal(hero.sensor, false);
  assert.deepEqual(hero.box.min.toArray(), [0.5, -0.5, -0.5]);
});

check("collisionWireboxes ignore rotation and grow only with scale", () => {
  const layout: RoomLayout = {
    schema: 1,
    name: "collision-rotation-fixture",
    loadGroups: [],
    instances: [
      {
        assetId: "wall",
        placements: [
          { position: [0, 0, 0] },
          { position: [4, 0, 0], rotationYDeg: 45 },
          { position: [8, 0, 0], rotationYDeg: 45, scale: [2, 1, 3] },
        ],
      },
    ],
    characters: [],
    lights: [],
  };
  const wallBounds = new Box3(new Vector3(-1, 0, -0.1), new Vector3(1, 2, 0.1));
  const boxes = collisionWireboxes(layout, new Map([["wall", wallBounds]]));

  assert.deepEqual(boxes[0]?.box.getSize(new Vector3()).toArray(), [2, 2, 0.2]);
  assert.deepEqual(boxes[1]?.box.getSize(new Vector3()).toArray(), [2, 2, 0.2]);
  const scaledSize = boxes[2]?.box.getSize(new Vector3()).toArray() ?? [];
  assert.ok(Math.abs((scaledSize[0] ?? 0) - 4) < 1e-9);
  assert.ok(Math.abs((scaledSize[1] ?? 0) - 2) < 1e-9);
  assert.ok(Math.abs((scaledSize[2] ?? 0) - 0.6) < 1e-9);
});

