check("behavior event bindings dispatch overlap and hit begin/end edges", () => {
  const events: string[] = [];
  const registry: BehaviorRegistry = {
    get: () => (context) => {
      events.push(
        `${context.entityId}:${context.event?.kind}:${context.event?.phase}:${context.event?.otherEntityId}`,
      );
    },
  };
  const physics = new PhysicsSubsystem();
  const sensor: Entity = {
    id: "sensor",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: true },
      [EVENT_BINDINGS_COMPONENT]: {
        bindings: [{ event: "overlap", scriptId: "record" }],
      },
    },
  };
  const blocker: Entity = {
    id: "blocker",
    components: {
      Transform: { position: [4, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: false },
      [EVENT_BINDINGS_COMPONENT]: {
        bindings: [{ event: "hit", scriptId: "record" }],
      },
    },
  };
  const player: Entity = {
    id: "player",
    components: {
      Transform: { position: [10, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  physics.setEntities([sensor, blocker, player]);
  const behavior = new BehaviorSubsystem(registry, new ActionMap({}), () => undefined, physics);
  behavior.setEntities([sensor, blocker, player]);
  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);

  app.update(0.016);
  assert.deepEqual(events, []);

  physics.setEntityTransform("player", {
    position: [0, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  app.update(0.016);
  app.update(0.016);
  assert.deepEqual(events, ["sensor:overlap:begin:player"]);

  physics.setEntityTransform("player", {
    position: [10, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  app.update(0.016);
  assert.deepEqual(events, ["sensor:overlap:begin:player", "sensor:overlap:end:player"]);

  physics.setEntityTransform("player", {
    position: [4, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  app.update(0.016);
  physics.setEntityTransform("player", {
    position: [10, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  app.update(0.016);
  assert.deepEqual(events, [
    "sensor:overlap:begin:player",
    "sensor:overlap:end:player",
    "blocker:hit:begin:player",
    "blocker:hit:end:player",
  ]);
});

check("dynamic physics active area classifies bodies outside its finite radius", () => {
  assert.equal(isOutsideDynamicActiveArea([10, 0, 0], [0, 0, 0], 10), false);
  assert.equal(isOutsideDynamicActiveArea([10.01, 0, 0], [0, 0, 0], 10), true);
  assert.equal(isOutsideDynamicActiveArea([0, 0, 11], [0, 0, 0], 10), true);
  assert.equal(isOutsideDynamicActiveArea([0, 0, 0], [0, 0, 0], 0), false);
  assert.equal(isOutsideDynamicActiveArea([Number.NaN, 0, 0], [0, 0, 0], 10), false);
});

check("LOD templates preserve authored distances while quality bias retunes them", () => {
  assert.equal(normalizeLodBias(undefined), 1);
  assert.equal(normalizeLodBias(0), 1);
  assert.equal(biasedLodDistance(40, 0.5), 20);
  const template = createLodTemplate([
    { distance: 40, object: new Group() },
    { distance: 0, object: new Group() },
    { distance: 100, object: new Group() },
  ], 0.5);
  assert.deepEqual(template.levels.map((level) => level.distance), [0, 20, 50]);

  const root = new Group();
  root.add(template);
  assert.equal(applyLodBias(root, 0.25), 1);
  assert.deepEqual(template.levels.map((level) => level.distance), [0, 10, 25]);
  assert.equal(applyLodBias(new Group(), 0.25), 0);
});

