// A `walkable` staircase's vertical riser triangles are still EMITTED as nav
// blockers (a solid walkable top can only seed ground via a blocker top, so the
// list must stay complete for ground probing) but each carries `navigationRole:
// "walkable"` so grid erosion can exclude them. Physics collision is unaffected.
check("walkable stair emits riser nav blockers tagged with their role; auto does not", () => {
  // One flat tread (y=0.2) + one vertical riser wall triangle (in the z=0 plane).
  const stairMesh = {
    shape: "trimesh" as const,
    size: [1, 0.2, 1] as [number, number, number],
    vertices: [
      [-0.5, 0.2, 0],
      [0.5, 0.2, 0],
      [0, 0.2, 0.5],
      [-0.5, 0, 0],
      [0.5, 0, 0],
      [-0.5, 0.2, 0],
    ] as [number, number, number][],
    indices: [0, 2, 1, 3, 4, 5], // CCW up-facing tread (signed +1); riser stays vertical
  };
  const makeStair = (navigationRole: "walkable" | "auto") => ({
    id: "stair",
    components: {
      Transform: {
        position: [0, 0, 0] as [number, number, number],
        rotation: [0, 0, 0] as [number, number, number],
        scale: [1, 1, 1] as [number, number, number],
      },
      Collider: {
        shape: "box" as const,
        size: [1, 0.2, 1] as [number, number, number],
        isStatic: true,
        isSensor: false,
        navigationRole,
        primitives: [stairMesh],
      },
    },
  });

  const walkable = new PhysicsSubsystem();
  walkable.setEntities([makeStair("walkable")]);
  const navBlockers = walkable.staticNavigationBlockerAabbs();
  assert.ok(
    navBlockers.length >= 1,
    "walkable riser is still emitted, so a solid walkable top can seed ground",
  );
  assert.ok(
    navBlockers.every((b) => b.navigationRole === "walkable"),
    "each walkable nav blocker carries its role so grid erosion can exclude it",
  );
  assert.ok(
    walkable.staticNavigationSurfaceTriangles().length >= 1,
    "walkable stair still seeds a walkable nav surface (the tread)",
  );
  assert.ok(
    walkable.staticBlockerAabbs().length >= 1,
    "physics collision is unaffected: the pawn still collides with / steps up the riser",
  );

  const auto = new PhysicsSubsystem();
  auto.setEntities([makeStair("auto")]);
  const autoBlockers = auto.staticNavigationBlockerAabbs();
  assert.ok(autoBlockers.length >= 1, "auto stair still walls the riser (geometry-derived)");
  assert.ok(
    autoBlockers.every((b) => b.navigationRole !== "walkable"),
    "auto blockers are not tagged walkable, so erosion keeps walling them",
  );
});

// End-to-end demonstration of the role fix: identical riser blockers erode the
// tread strip (untagged -> the bug) but are excluded from erosion when tagged
// `walkable` (the fix), while ground seeding via `sampleFloorY` is untouched.
// Real asset geometry: 0.2 m rise, 0.24 m tread, agent radius 0.35 + clearance
// 0.1 + safety 0.25 = 0.70 m. The stair is modelled wide (|z| <= 2 m) because
// ledge erosion now insets each flank by the clearance radius; a real staircase
// wider than the agent keeps a navigable interior, whereas a one-cell strip would
// (correctly) be entirely inside the fall border.
check("nav grid erosion excludes walkable blockers so a walkable staircase is climbable", () => {
  const rise = 0.2;
  const tread = 0.24;
  const nSteps = 8;
  const agent = { radius: 0.35, height: 1.8, stepHeight: 0.5, maxStepDown: 0.5, clearancePadding: 0.1 };
  const runLength = nSteps * tread;
  const bounds: NavAabb[] = [{ min: [-2, -1, -3], max: [runLength + 2, 3, 3] }];
  // A wide stair corridor along +X; null off the strip so there is no way around.
  const sampleFloorY = (x: number, z: number): number | null => {
    if (Math.abs(z) > 2) return null;
    const step = Math.min(nSteps, Math.max(0, Math.round(x / tread)));
    return step * rise;
  };
  // One vertical riser wall (thin AABB + line footprint) at each step's front edge,
  // spanning the full stair width so untagged erosion walls the whole corridor.
  const risers: NavBlocker[] = [];
  for (let k = 1; k <= nSteps; k += 1) {
    const edgeX = k * tread - tread / 2;
    risers.push({
      min: [edgeX - 0.02, (k - 1) * rise, -3],
      max: [edgeX + 0.02, k * rise, 3],
      footprint: [
        [edgeX, -3],
        [edgeX, 3],
      ],
    });
  }
  const start: Vec3 = [0, 0, 0];
  const goal: Vec3 = [runLength, nSteps * rise, 0];

  const walled = buildNavGrid({ agent, blockers: risers, bounds, footY: 0, cellSize: tread, safetyMargin: 0.25, sampleFloorY });
  assert.ok(walled, "walled grid builds");
  assert.equal(
    searchNavGrid(walled!, start, goal).status,
    "failure",
    "untagged risers erode the tread strip -> staircase unreachable (the bug)",
  );

  const walkableRisers: NavBlocker[] = risers.map((r) => ({ ...r, navigationRole: "walkable" as const }));
  const climbable = buildNavGrid({ agent, blockers: walkableRisers, bounds, footY: 0, cellSize: tread, safetyMargin: 0.25, sampleFloorY });
  assert.ok(climbable, "walkable grid builds");
  assert.equal(
    searchNavGrid(climbable!, start, goal).status,
    "success",
    "walkable-tagged risers are excluded from erosion -> identical heightfield is navigable",
  );
});

// A collider with a center offset places its AABB at position + center, so a
// model whose geometry is not centered on its origin still aligns to the mesh.
check("physics subsystem offsets a collider AABB by its center", () => {
  const physics = new PhysicsSubsystem();
  physics.setEntities([
    {
      id: "wall",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        Collider: {
          shape: "box",
          size: [2, 4, 0.5],
          center: [0, 2, 1],
          isStatic: true,
          isSensor: false,
        },
      },
    },
  ]);
  assert.deepEqual(physics.staticBlockerAabbs()[0], {
    min: [-1, 0, 0.75],
    max: [1, 4, 1.25],
  });
});

function assertAabbClose(
  actual: { min: readonly number[]; max: readonly number[] },
  expected: { min: readonly number[]; max: readonly number[] },
  eps = 1e-9,
): void {
  for (let i = 0; i < 3; i += 1) {
    assert.ok(
      Math.abs((actual.min[i] ?? NaN) - (expected.min[i] ?? NaN)) < eps,
      `min[${i}]=${actual.min[i]} expected ${expected.min[i]}`,
    );
    assert.ok(
      Math.abs((actual.max[i] ?? NaN) - (expected.max[i] ?? NaN)) < eps,
      `max[${i}]=${actual.max[i]} expected ${expected.max[i]}`,
    );
  }
}

// P1.2 — the movement-blocker AABB must honour placement rotation. Collider
// size/center is authored in the body-local frame; a corner-pivoted wall (centre
// offset [2,1.5,0]) rotated to face another way must land where it is drawn, not
// several metres off along the un-rotated offset (the root cause of walking
// through real walls while being blocked on open floor).
check("rotatedBoxAabb: zero rotation returns the plain body-local box", () => {
  const aabb = rotatedBoxAabb([0, 0, 0], [2, 1.5, 0], [2, 1.5, 0.1], [0, 0, 0]);
  assert.deepEqual(aabb, { min: [0, 0, -0.1], max: [4, 3, 0.1] });
});

check("rotatedBoxAabb: a corner-pivoted wall rotated 90° about Y follows the mesh", () => {
  // Wall_400x300-style box: half [2,1.5,0.1], centre offset [2,1.5,0].
  const aabb = rotatedBoxAabb([0, 0, 0], [2, 1.5, 0], [2, 1.5, 0.1], [0, 90, 0]);
  // +90°Y swings the local +X centre to world -Z and the thin axis becomes X.
  assertAabbClose(aabb, { min: [-0.1, 0, -4], max: [0.1, 3, 0] });
});

check("rotatedBoxAabb: 45° rotation bloats a thin wall's footprint symmetrically", () => {
  const aabb = rotatedBoxAabb([0, 0, 0], [0, 0, 0], [2, 1.5, 0.1], [0, 45, 0]);
  const expectedHalf = Math.SQRT1_2 * (2 + 0.1);
  assertAabbClose(aabb, {
    min: [-expectedHalf, -1.5, -expectedHalf],
    max: [expectedHalf, 1.5, expectedHalf],
  });
});

check("rotatedBoxFootprintXZ: undefined for an axis-aligned box, area-tight for a rotated one", () => {
  // An axis-aligned box's ground silhouette is exactly its min.xz..max.xz rect,
  // so nav keeps the cheaper AABB path — no footprint is emitted.
  assert.equal(rotatedBoxFootprintXZ([0, 0, 0], [0, 0, 0], [2, 1.5, 0.1], [0, 0, 0]), undefined);

  // A 45°-rotated thin wall: the footprint is the true (rotation-preserving) area,
  // strictly smaller than the square AABB that encloses it — the bloat OBB avoids.
  const half: [number, number, number] = [2, 1.5, 0.1];
  const footprint = rotatedBoxFootprintXZ([0, 0, 0], [0, 0, 0], half, [0, 45, 0]);
  assert.ok(footprint && footprint.length >= 3);
  let area2 = 0;
  for (let i = 0; i < footprint!.length; i += 1) {
    const p = footprint![i]!;
    const q = footprint![(i + 1) % footprint!.length]!;
    area2 += p[0] * q[1] - q[0] * p[1];
  }
  const footprintArea = Math.abs(area2) / 2;
  const trueArea = 2 * half[0] * (2 * half[2]); // 2*2 by 2*0.1 = 0.8
  assert.ok(Math.abs(footprintArea - trueArea) < 1e-6, `footprint area ${footprintArea} ~= ${trueArea}`);
  const aabb = rotatedBoxAabb([0, 0, 0], [0, 0, 0], half, [0, 45, 0]);
  const aabbArea = (aabb.max[0] - aabb.min[0]) * (aabb.max[2] - aabb.min[2]);
  assert.ok(aabbArea > footprintArea + 1, `enclosing AABB ${aabbArea} bloats past footprint ${footprintArea}`);
});

check("rotatedBoxAabb: primitive rotation composes on top of body rotation", () => {
  // A box with a local +90°Y primitive rotation, under a further +90°Y body
  // rotation, is oriented +180° total: thin Z axis stays Z, extents swap back.
  const aabb = rotatedBoxAabb([0, 0, 0], [0, 0, 0], [2, 1.5, 0.1], [0, 90, 0], [0, 90, 0]);
  assertAabbClose(aabb, { min: [-2, -1.5, -0.1], max: [2, 1.5, 0.1] });
});

