// A5 SpawnActor: the engine surface is still host-owned. A behavior queues the
// class ref + transform + exposed params; the runtime shell resolves the class
// async and incrementally adds render/physics/behavior.
check("actor command: spawn delivers a cloned host request", () => {
  const requests: Array<{
    sourceEntityId: string;
    classRef: string;
    transform: { position: number[]; rotation: number[]; scale: number[] };
    params?: Record<string, unknown>;
  }> = [];
  const registry: BehaviorRegistry = {
    get: () => (context) => {
      if (context.state.get("spawned", false)) return;
      context.state.set("spawned", true);
      const transform = {
        position: [1, 2, 3],
        rotation: [0, 90, 0],
        scale: [2, 2, 2],
      } as const;
      const params = { damage: 12, nested: { team: "blue" } };
      context.actor.spawn("Blueprints/Projectile.actor.json", transform, params);
      (transform.position as number[])[0] = 99;
      params.damage = 99;
      params.nested.team = "red";
    },
  };
  const entity: Entity = {
    id: "actor:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Behavior: { scriptId: "spawner", params: {} },
    },
  };
  const behavior = new BehaviorSubsystem(
    registry,
    new ActionMap({}),
    () => undefined,
    undefined,
    undefined,
    {
      actorCommandSink: {
        setVisibility: () => undefined,
        destroy: () => undefined,
        spawn: (request) => {
          requests.push(request);
        },
      },
    },
  );
  behavior.setEntities([entity]);
  behavior.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });

  assert.deepEqual(requests, [
    {
      sourceEntityId: "actor:0",
      classRef: "Blueprints/Projectile.actor.json",
      transform: { position: [1, 2, 3], rotation: [0, 90, 0], scale: [2, 2, 2] },
      params: { damage: 12, nested: { team: "blue" } },
    },
  ]);
});

check("runtime spawn: addEntity joins behavior, physics, messages and destroy cleanup", () => {
  const events: string[] = [];
  const registry: BehaviorRegistry = {
    get: (scriptId) => {
      if (scriptId === "begin") return (context) => events.push(`begin:${context.entityId}`);
      if (scriptId === "tick") return (context) => events.push(`tick:${context.entityId}`);
      if (scriptId === "overlap") {
        return (context) => {
          events.push(`${context.event?.phase}:${context.entityId}:${context.event?.otherEntityId}`);
        };
      }
      if (scriptId === "ping") return (context) => events.push(`ping:${context.entityId}`);
      if (scriptId === "destroy") return (context) => context.actor.destroy();
      return undefined;
    },
  };
  const player: Entity = {
    id: "player:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  const spawned: Entity = {
    id: spawnedActorEntityId(0),
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: true },
      ScriptActor: { classRef: "Blueprints/Pickup.actor.json" },
      EventBindings: {
        bindings: [
          { event: "beginPlay", scriptId: "begin" },
          { event: "tick", scriptId: "tick" },
          { event: "overlap", scriptId: "overlap" },
        ],
      },
      MessageBindings: {
        bindings: [
          { message: "Ping", scriptId: "ping", target: "self" },
          { message: "Destroy", scriptId: "destroy", target: "self" },
        ],
      },
    },
  };
  const physics = new PhysicsSubsystem();
  physics.setEntities([player]);
  const destroyed: string[] = [];
  const behavior = new BehaviorSubsystem(
    registry,
    new ActionMap({}),
    () => undefined,
    physics,
    undefined,
    {
      actorCommandSink: {
        setVisibility: () => undefined,
        destroy: (id) => {
          destroyed.push(id);
          physics.removeEntity(id);
        },
      },
    },
  );
  behavior.setEntities([player]);
  assert.equal(physics.addEntity(spawned), true);
  assert.equal(behavior.addEntity(spawned), true);
  assert.equal(behavior.addEntity(spawned), false, "duplicate spawned ids are rejected");
  assert.equal(behavior.getScriptActorDebugInfo("spawned:0")?.classRef, "Blueprints/Pickup.actor.json");

  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);
  app.update(0.016);
  assert.deepEqual(events, [
    "begin:spawned:0",
    "tick:spawned:0",
    "begin:spawned:0:player:0",
  ]);

  behavior.emitScriptMessage("Ping", "player:0", undefined, "spawned:0");
  app.update(0.016);
  assert.ok(events.includes("ping:spawned:0"));
  assert.ok(events.includes("tick:spawned:0"));

  behavior.emitScriptMessage("Destroy", "player:0", undefined, "spawned:0");
  app.update(0.016);
  assert.deepEqual(destroyed, ["spawned:0"]);
  assert.deepEqual(physics.contactsForEntity("spawned:0"), []);

  const eventCountAfterDestroy = events.length;
  behavior.emitScriptMessage("Ping", "player:0", undefined, "spawned:0");
  app.update(0.016);
  assert.equal(events.length, eventCountAfterDestroy);

  behavior.setEntities([player]);
  assert.equal(behavior.getScriptActorDebugInfo("spawned:0"), null);
});

check("proximity-toggle behavior emits edges from ScriptWorld distance queries", () => {
  const events: string[] = [];
  const behavior = new BehaviorSubsystem(
    createBehaviorRegistry(),
    new ActionMap({}),
    () => undefined,
  );
  const watcher: Entity = {
    id: "watcher",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Behavior: { scriptId: "proximity-toggle", params: { targetTag: "player", range: 2 } },
    },
  };
  const player: Entity = {
    id: "player",
    tags: ["player"],
    components: {
      Transform: { position: [5, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
    },
  };
  behavior.setEntities([watcher, player]);
  behavior.subscribeScriptMessage("Proximity.Changed", (envelope) => {
    events.push(`${String(envelope.payload.entityId)}:${String(envelope.payload.target)}:${String(envelope.payload.near)}`);
  });

  behavior.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  assert.deepEqual(events, []);
  behavior.resetEntityTransform("player", {
    position: [1, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  behavior.update({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 });
  behavior.update({ deltaSeconds: 0.016, elapsedSeconds: 0.048, frame: 3 });
  behavior.resetEntityTransform("player", {
    position: [4, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  behavior.update({ deltaSeconds: 0.016, elapsedSeconds: 0.064, frame: 4 });

  assert.deepEqual(events, ["watcher:player:true", "watcher:player:false"]);
});

// Â§3 Interaction runtime: the pure trigger core decides fire/cooldown; the
// `interact` behavior drives it from physics sensor contacts + the authored
// InteractionComponent, reusing the goal-reached sensor pattern.
check("stepInteractionTrigger: fires on a fresh enter, not while held, re-fires on re-enter", () => {
  let state = initialInteractionState();
  let r = stepInteractionTrigger(state, { overlapping: false, enabled: true, cooldown: 0, dt: 0.016 });
  assert.equal(r.fire, false);
  state = r.state;
  // Fresh enter fires.
  r = stepInteractionTrigger(state, { overlapping: true, enabled: true, cooldown: 0, dt: 0.016 });
  assert.equal(r.fire, true);
  state = r.state;
  // Held overlap does not re-fire.
  r = stepInteractionTrigger(state, { overlapping: true, enabled: true, cooldown: 0, dt: 0.016 });
  assert.equal(r.fire, false);
  state = r.state;
  // Leave, then re-enter with no cooldown: fires again.
  state = stepInteractionTrigger(state, { overlapping: false, enabled: true, cooldown: 0, dt: 0.016 }).state;
  r = stepInteractionTrigger(state, { overlapping: true, enabled: true, cooldown: 0, dt: 0.016 });
  assert.equal(r.fire, true);
});

check("stepInteractionTrigger: disabled never fires; cooldown blocks re-fire until it decays", () => {
  // Disabled: a fresh enter does not fire.
  assert.equal(
    stepInteractionTrigger(initialInteractionState(), {
      overlapping: true,
      enabled: false,
      cooldown: 0,
      dt: 0.016,
    }).fire,
    false,
  );

  // Fire with a 1s cooldown.
  let r = stepInteractionTrigger(initialInteractionState(), {
    overlapping: true,
    enabled: true,
    cooldown: 1,
    dt: 0.016,
  });
  assert.equal(r.fire, true);
  assert.ok(r.state.cooldownRemaining > 0);
  // Leave (cooldown decays partway).
  let state = stepInteractionTrigger(r.state, { overlapping: false, enabled: true, cooldown: 1, dt: 0.5 }).state;
  // Re-enter before cooldown elapses: blocked.
  r = stepInteractionTrigger(state, { overlapping: true, enabled: true, cooldown: 1, dt: 0.1 });
  assert.equal(r.fire, false);
  // Leave again and let the rest elapse, then re-enter: fires.
  state = stepInteractionTrigger(r.state, { overlapping: false, enabled: true, cooldown: 1, dt: 1 }).state;
  assert.equal(state.cooldownRemaining, 0);
  assert.equal(
    stepInteractionTrigger(state, { overlapping: true, enabled: true, cooldown: 1, dt: 0.016 }).fire,
    true,
  );
});

check("interact behavior: fires the action + cue on a sensor enter, not while held", () => {
  const fired: Array<{ id: string; action: string }> = [];
  const registry = createBehaviorRegistry({
    onInteraction: (id, action) => fired.push({ id, action }),
  });
  const physics = new PhysicsSubsystem();
  const audio = new AudioSubsystem();
  const lever: Entity = {
    id: "lever:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: true },
      Behavior: { scriptId: "interact" },
      Interaction: { action: "pull-lever", prompt: "Pull" },
      Audio: { clipId: "collision-chime", volume: 0.5, loop: false, spatial: false },
    },
  };
  const player: Entity = {
    id: "player:0",
    components: {
      Transform: { position: [5, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  physics.setEntities([lever, player]);
  const behavior = new BehaviorSubsystem(registry, new ActionMap({}), () => undefined, physics, audio);
  behavior.setEntities([lever, player]);
  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);
  app.registerSubsystem(audio);

  // A sensor never blocks movement, and far apart there is no contact.
  assert.equal(physics.staticBlockerAabbs().length, 0);
  app.update(0.016);
  assert.deepEqual(fired, []);

  // Enter the sensor and tick twice: it fires exactly once.
  physics.setEntityTransform("player:0", { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] });
  app.update(0.016);
  app.update(0.016);
  assert.deepEqual(fired, [{ id: "lever:0", action: "pull-lever" }]);
  assert.deepEqual(audio.playedRequests(), [
    { clipId: "collision-chime", volume: 0.5, loop: false, spatial: false },
  ]);
});

