// P4 Boot / Loading UX: pure progress aggregator.
check("load progress: counts loaded/failed/pending and derives fraction + done", () => {
  const tracker = new LoadProgressTracker();
  // Empty is immediately complete (nothing to wait for).
  assert.deepEqual(tracker.snapshot(), {
    total: 0,
    loaded: 0,
    failed: 0,
    pending: 0,
    fraction: 1,
    done: true,
    failedIds: [],
  });

  tracker.expectAll(["model-a", "model-b", { id: "tex-c", label: "Texture C" }, "audio-d"]);
  let snap = tracker.snapshot();
  assert.equal(snap.total, 4);
  assert.equal(snap.pending, 4);
  assert.equal(snap.fraction, 0);
  assert.equal(snap.done, false);

  tracker.markLoaded("model-a");
  tracker.markLoaded("model-b");
  snap = tracker.snapshot();
  assert.equal(snap.loaded, 2);
  assert.equal(snap.fraction, 0.5);
  assert.equal(snap.done, false);

  tracker.markFailed("tex-c", "404 Not Found");
  snap = tracker.snapshot();
  assert.equal(snap.failed, 1);
  assert.deepEqual(snap.failedIds, ["tex-c"]);
  // Settled (loaded+failed) counts toward the bar even though one failed.
  assert.equal(snap.fraction, 0.75);
  assert.equal(snap.done, false);

  tracker.markLoaded("audio-d");
  snap = tracker.snapshot();
  assert.equal(snap.done, true);
  assert.equal(snap.fraction, 1);
  assert.equal(snap.pending, 0);

  // Label from expectAll survives; the failed item carries its reason.
  const failed = tracker.entries().find((item) => item.id === "tex-c");
  assert.equal(failed?.label, "Texture C");
  assert.equal(failed?.error, "404 Not Found");
});

check("load progress: transitions are idempotent and retry moves failed -> loaded", () => {
  const tracker = new LoadProgressTracker();
  tracker.expect("m1");

  // Auto-registration: reporting an undeclared id grows the total.
  tracker.markLoaded("m2");
  let snap = tracker.snapshot();
  assert.equal(snap.total, 2);
  assert.equal(snap.loaded, 1);

  // Re-reporting a loaded item does not double-count.
  tracker.markLoaded("m2");
  assert.equal(tracker.snapshot().loaded, 1);

  tracker.markFailed("m1", "network");
  snap = tracker.snapshot();
  assert.equal(snap.failed, 1);
  assert.equal(snap.loaded, 1);

  // resetFailed rewinds failed items to pending for a retry pass.
  tracker.resetFailed();
  snap = tracker.snapshot();
  assert.equal(snap.failed, 0);
  assert.equal(snap.pending, 1);
  assert.deepEqual(snap.failedIds, []);

  // Retry succeeds: the same id settles as loaded, completing the set.
  tracker.markLoaded("m1");
  snap = tracker.snapshot();
  assert.equal(snap.loaded, 2);
  assert.equal(snap.done, true);
});

check("load progress: formatLoadDetail renders settled/total with a failure suffix", () => {
  const tracker = new LoadProgressTracker();
  assert.equal(formatLoadDetail(tracker.snapshot()), "");
  tracker.expectAll(["a", "b", "c"]);
  assert.equal(formatLoadDetail(tracker.snapshot()), "0 / 3");
  tracker.markLoaded("a");
  assert.equal(formatLoadDetail(tracker.snapshot()), "1 / 3");
  tracker.markFailed("b", "boom");
  assert.equal(formatLoadDetail(tracker.snapshot()), "2 / 3 · 1 failed");
});

check("load progress: subscribe fires immediately and on each change, clear resets", () => {
  const tracker = new LoadProgressTracker();
  tracker.expect("only");
  const seen: number[] = [];
  const unsubscribe = tracker.subscribe((snap) => seen.push(snap.loaded));
  // Immediate fire with the current snapshot.
  assert.deepEqual(seen, [0]);
  tracker.markLoaded("only");
  assert.deepEqual(seen, [0, 1]);
  // No-op transition does not notify.
  tracker.markLoaded("only");
  assert.deepEqual(seen, [0, 1]);
  unsubscribe();
  tracker.clear();
  // After unsubscribe, no further notifications; tracker is empty again.
  assert.deepEqual(seen, [0, 1]);
  assert.deepEqual(tracker.snapshot(), {
    total: 0,
    loaded: 0,
    failed: 0,
    pending: 0,
    fraction: 1,
    done: true,
    failedIds: [],
  });
});

// ---------------------------------------------------------------------------
// P5 Performance Infrastructure: subsystem profiler, perf budget, asset report.
// ---------------------------------------------------------------------------

check("subsystem profiler: rolling average sorts worst-first with last + peak", () => {
  const profiler = new SubsystemProfiler(4); // small window for the test
  // physics is consistently the most expensive; behavior cheapest.
  profiler.record("physics", 2);
  profiler.record("behavior", 0.5);
  profiler.record("animation", 1);
  profiler.endFrame();
  profiler.record("physics", 4);
  profiler.record("behavior", 0.5);
  profiler.record("animation", 1);
  profiler.endFrame();

  const snapshot = profiler.snapshot();
  assert.equal(snapshot.frames, 2);
  assert.deepEqual(
    snapshot.subsystems.map((s) => s.id),
    ["physics", "animation", "behavior"],
  );
  const physics = snapshot.subsystems[0]!;
  assert.equal(physics.averageMs, 3); // (2 + 4) / 2
  assert.equal(physics.lastMs, 4);
  assert.equal(physics.maxMs, 4);
  assert.equal(physics.samples, 2);
  // totalAverageMs sums every subsystem's rolling average (3 + 1 + 0.5).
  assert.equal(snapshot.totalAverageMs, 4.5);
});

check("subsystem profiler: window drops old samples, clamps negatives, top(n) + clear", () => {
  const profiler = new SubsystemProfiler(2); // window of 2 frames
  profiler.record("a", 10);
  profiler.record("a", 20);
  profiler.record("a", 30); // evicts the 10 → window holds [20, 30]
  assert.equal(profiler.snapshot().subsystems[0]!.averageMs, 25);
  assert.equal(profiler.snapshot().subsystems[0]!.maxMs, 30);

  // Negative (clock skew) samples clamp to 0 rather than corrupting the mean.
  const skew = new SubsystemProfiler(2);
  skew.record("s", -5);
  skew.record("s", 5);
  assert.equal(skew.snapshot().subsystems[0]!.averageMs, 2.5);

  const many = new SubsystemProfiler();
  many.record("x", 1);
  many.record("y", 9);
  many.record("z", 5);
  assert.deepEqual(
    many.top(2).map((t) => t.id),
    ["y", "z"],
  );
  many.clear();
  assert.deepEqual(many.snapshot(), { subsystems: [], totalAverageMs: 0, frames: 0 });
});

check("subsystem profiler: registry times each subsystem with an injected clock", () => {
  const app = new EngineApp();
  const ticks: string[] = [];
  const makeSubsystem = (id: string): Subsystem => ({
    id,
    update: () => {
      ticks.push(id);
    },
  });
  app.registerSubsystem(makeSubsystem("first"));
  app.registerSubsystem(makeSubsystem("second"));

  // Deterministic clock: each now() call advances 1ms, so every subsystem's
  // measured (end - start) is exactly 1ms.
  let clock = 0;
  const profiler = app.enableProfiling(() => (clock += 1));
  assert.equal(profiler instanceof SubsystemProfiler, true);
  // Idempotent: a second enable returns the same profiler.
  assert.equal(app.enableProfiling(), profiler);

  app.update(0.016);
  assert.deepEqual(ticks, ["first", "second"]);
  const snapshot = app.getProfileSnapshot();
  assert.ok(snapshot);
  assert.equal(snapshot!.frames, 1);
  assert.deepEqual(
    snapshot!.subsystems.map((s) => [s.id, s.lastMs]),
    [
      ["first", 1],
      ["second", 1],
    ],
  );
});

