// AI (Faz 1): Blackboard memory, AIController, AISubsystem, component reader.
// ---------------------------------------------------------------------------

check("Blackboard applies declared defaults and rejects unknown/mistyped writes", () => {
  const bb = new Blackboard([
    { key: "target", kind: "entity", default: null },
    { key: "hasLineOfSight", kind: "boolean", default: false },
    { key: "aggro", kind: "number" },
    { key: "patrolPoint", kind: "vec3", default: null },
  ]);
  // Declared defaults (and each kind's zero value when no default is authored).
  assert.equal(bb.getEntity("target"), null);
  assert.equal(bb.getBoolean("hasLineOfSight"), false);
  assert.equal(bb.getNumber("aggro"), 0);
  assert.equal(bb.getVec3("patrolPoint"), null);
  assert.equal(bb.keyCount(), 4);
  // Typed writes update and read back.
  assert.equal(bb.set("hasLineOfSight", true), true);
  assert.equal(bb.getBoolean("hasLineOfSight"), true);
  assert.equal(bb.set("target", "enemy-1"), true);
  assert.equal(bb.getEntity("target"), "enemy-1");
  assert.equal(bb.set("aggro", 5), true);
  assert.equal(bb.getNumber("aggro"), 5);
  // An undeclared key can never be written (no phantom keys).
  assert.equal(bb.set("nope", true), false);
  assert.equal(bb.has("nope"), false);
  assert.equal(bb.get("nope"), undefined);
  // A wrong-typed write is a no-op; the prior value stands.
  assert.equal(bb.set("hasLineOfSight", "yes"), false);
  assert.equal(bb.getBoolean("hasLineOfSight"), true);
});

check("Blackboard clones vec3 in/out (no aliasing) and reset restores defaults", () => {
  const bb = new Blackboard([
    { key: "patrolPoint", kind: "vec3", default: [1, 2, 3] },
    { key: "hasLineOfSight", kind: "boolean", default: false },
  ]);
  const read = bb.getVec3("patrolPoint");
  assert.deepEqual(read, [1, 2, 3]);
  // Mutating the returned tuple must not reach the store.
  if (read) read[0] = 99;
  assert.deepEqual(bb.getVec3("patrolPoint"), [1, 2, 3]);
  // A caller-owned array is copied in, not aliased.
  const src: [number, number, number] = [4, 5, 6];
  bb.set("patrolPoint", src);
  src[1] = 0;
  assert.deepEqual(bb.getVec3("patrolPoint"), [4, 5, 6]);
  bb.set("hasLineOfSight", true);
  assert.equal(bb.clear("patrolPoint"), true);
  assert.equal(bb.getVec3("patrolPoint"), null);
  bb.reset();
  assert.deepEqual(bb.getVec3("patrolPoint"), [1, 2, 3]);
  assert.equal(bb.getBoolean("hasLineOfSight"), false);
});

check("normalizeBlackboardKeys keeps valid keys, drops malformed, dedupes", () => {
  const keys: BlackboardKeyDef[] = normalizeBlackboardKeys([
    { key: "target", kind: "entity", default: null },
    { key: "speed", kind: "number", default: 2 },
    { key: "target", kind: "boolean" }, // duplicate key dropped
    { key: "", kind: "number" }, // empty key dropped
    { key: "bad", kind: "banana" }, // unknown kind dropped
    { key: "loose", kind: "vec3", default: [1, 2] }, // bad default dropped, key kept
    "nope",
  ]);
  assert.deepEqual(
    keys.map((entry) => entry.key),
    ["target", "speed", "loose"],
  );
  assert.equal(keys[0]?.kind, "entity");
  assert.equal(keys.find((entry) => entry.key === "loose")?.default, undefined);
});

check("AI blackboard asset normalizer validates schema, kinds, defaults, and duplicates", () => {
  const asset = normalizeAiBlackboardAsset({
    schema: 1,
    type: "blackboard",
    keys: [
      { key: "target", kind: "entity", default: null },
      { key: "patrolPoint", kind: "vec3", default: [1, 2, 3] },
      { key: "hasLineOfSight", kind: "boolean", default: false },
    ],
  });
  assert.equal(asset.type, "blackboard");
  assert.equal(asset.keys.length, 3);
  assert.deepEqual(asset.keys[1]?.default, [1, 2, 3]);
  assert.throws(
    () => normalizeAiBlackboardAsset({ schema: 1, type: "blackboard", keys: [{ key: "x", kind: "banana" }] }),
    /kind is invalid/,
  );
  assert.throws(
    () => normalizeAiBlackboardAsset({
      schema: 1,
      type: "blackboard",
      keys: [
        { key: "target", kind: "entity" },
        { key: "target", kind: "entity" },
      ],
    }),
    /duplicated/,
  );
  assert.throws(
    () => normalizeAiBlackboardAsset({
      schema: 1,
      type: "blackboard",
      keys: [{ key: "bad", kind: "number", default: "fast" }],
    }),
    /does not match kind/,
  );
});

check("AI behavior tree asset normalizer canonicalizes supported node shapes", () => {
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    blackboard: "assets/AI/Enemy.blackboard.json",
    root: {
      kind: "selector",
      children: [
        {
          kind: "sequence",
          decorators: [{ kind: "blackboard", key: "hasLineOfSight", op: "equals", value: true }],
          services: [{ service: "forge.updateTargetDistance", interval: 0.5, params: { key: "target" } }],
          children: [
            { kind: "task", task: "forge.sendMessage", params: { type: "enemy.alert", count: 1 } },
            { kind: "wait", seconds: 0.25 },
          ],
        },
        { kind: "subtree", behavior: "assets/AI/Idle.behavior.json" },
      ],
    },
  });
  assert.equal(asset.type, "behaviorTree");
  assert.equal(asset.blackboard, "assets/AI/Enemy.blackboard.json");
  const root = asset.root;
  if (root.kind !== "selector") throw new Error("expected selector root");
  assert.equal(root.children.length, 2);
  const first = root.children[0];
  assert.equal(first?.kind, "sequence");
  if (first?.kind === "sequence") {
    assert.equal(first.children[0]?.kind, "task");
    assert.equal(first.decorators?.[0]?.key, "hasLineOfSight");
    assert.equal(first.services?.[0]?.interval, 0.5);
  }
  assert.throws(
    () => normalizeAiBehaviorTreeAsset({ schema: 1, type: "behaviorTree", root: { kind: "task" } }),
    /task.task/,
  );
  assert.throws(
    () => normalizeAiBehaviorTreeAsset({
      schema: 1,
      type: "behaviorTree",
      root: {
        kind: "selector",
        children: [{ kind: "task", task: "x", decorators: [{ kind: "blackboard", key: "k", op: "equals" }] }],
      },
    }),
    /value is required/,
  );
});

check("AI behavior tree normalizer canonicalizes distance/cooldown/perception decorators", () => {
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "selector",
      children: [
        {
          kind: "task",
          task: "game.attack",
          decorators: [
            { kind: "distance", key: "target", op: "lte", value: 2.5 },
            { kind: "cooldown", seconds: 1.2345 },
            { kind: "hasPerceptionStimulus", sense: "sight", minStrength: 0.4, requireLineOfSight: true },
          ],
        },
        { kind: "task", task: "game.patrol" },
      ],
    },
  });
  const root = asset.root;
  if (root.kind !== "selector") throw new Error("expected selector root");
  const attack = root.children[0];
  const decorators = attack?.decorators ?? [];
  assert.equal(decorators[0]?.kind, "distance");
  const distance = decorators[0];
  if (distance?.kind === "distance") {
    assert.equal(distance.key, "target");
    assert.equal(distance.op, "lte");
    assert.equal(distance.value, 2.5);
  }
  const cooldown = decorators[1];
  if (cooldown?.kind === "cooldown") assert.equal(cooldown.seconds, 1.234); // toFixed(3)
  const perception = decorators[2];
  if (perception?.kind === "hasPerceptionStimulus") {
    assert.equal(perception.sense, "sight");
    assert.equal(perception.minStrength, 0.4);
    assert.equal(perception.requireLineOfSight, true);
  }

  const makeTree = (decorator: unknown) => ({
    schema: 1,
    type: "behaviorTree",
    root: { kind: "task", task: "x", decorators: [decorator] },
  });
  assert.throws(() => normalizeAiBehaviorTreeAsset(makeTree({ kind: "distance", key: "t", op: "near", value: 2 })), /op must be one of/);
  assert.throws(() => normalizeAiBehaviorTreeAsset(makeTree({ kind: "distance", key: "t", op: "lt" })), /value must be a finite number/);
  assert.throws(() => normalizeAiBehaviorTreeAsset(makeTree({ kind: "cooldown", seconds: 0 })), /positive number/);
  assert.throws(() => normalizeAiBehaviorTreeAsset(makeTree({ kind: "hasPerceptionStimulus", sense: "smell" })), /sense is invalid/);
  assert.throws(() => normalizeAiBehaviorTreeAsset(makeTree({ kind: "telepathy" })), /kind is invalid/);
});

check("AI state tree asset normalizer canonicalizes hierarchical states", () => {
  const asset = normalizeAiStateTreeAsset({
    schema: 1,
    type: "stateTree",
    blackboard: "assets/AI/Enemy.blackboard.json",
    parameters: { routeTag: "outer", speed: 2, shared: true },
    context: { role: "guard", home: [1, 0, 2] },
    evaluators: [{ service: "forge.updatePerceptionBlackboard", interval: 0.25 }],
    states: [
      {
        id: "Patrol",
        tasks: [{ task: "game.patrol", params: { loop: true } }],
        transitions: [
          {
            to: "Chase",
            conditions: [{ kind: "hasPerceptionStimulus", sense: "sight", requireLineOfSight: true }],
          },
        ],
        states: [{ id: "PatrolWait", tasks: [{ task: "forge.wait" }] }],
      },
      {
        id: "Chase",
        enter: [{ kind: "distance", key: "target", op: "lte", value: 20 }],
        transitions: [{ to: "Patrol", event: "target-lost" }],
      },
    ],
  });
  assert.equal(asset.type, "stateTree");
  assert.equal(asset.blackboard, "assets/AI/Enemy.blackboard.json");
  assert.deepEqual(asset.parameters, { routeTag: "outer", speed: 2, shared: true });
  assert.deepEqual(asset.context, { role: "guard", home: [1, 0, 2] });
  assert.equal(asset.evaluators?.[0]?.service, "forge.updatePerceptionBlackboard");
  assert.equal(asset.states.length, 2);
  const patrol = asset.states[0];
  assert.equal(patrol?.id, "Patrol");
  assert.equal(patrol?.tasks?.[0]?.task, "game.patrol");
  assert.equal(patrol?.transitions?.[0]?.to, "Chase");
  assert.equal(patrol?.states?.[0]?.id, "PatrolWait");
  const chase = asset.states[1];
  assert.equal(chase?.enter?.[0]?.kind, "distance");
  assert.equal(chase?.transitions?.[0]?.event, "target-lost");
});

check("AI state tree normalizer rejects malformed assets", () => {
  assert.throws(
    () => normalizeAiStateTreeAsset({ schema: 1, type: "stateTree", states: [] }),
    /non-empty array/,
  );
  assert.throws(
    () => normalizeAiStateTreeAsset({ schema: 2, type: "stateTree", states: [{ id: "A" }] }),
    /schema must be 1/,
  );
  assert.throws(
    () => normalizeAiStateTreeAsset({ schema: 1, type: "stateTree", states: [{ id: "A" }, { id: "A" }] }),
    /is duplicated/,
  );
  assert.throws(
    () =>
      normalizeAiStateTreeAsset({
        schema: 1,
        type: "stateTree",
        states: [{ id: "A", transitions: [{ to: "Missing" }] }],
      }),
    /references unknown state/,
  );
  assert.throws(
    () => normalizeAiStateTreeAsset({ schema: 1, type: "stateTree", states: [{ tasks: [] }] }),
    /\.id must be a non-empty string/,
  );
  assert.throws(
    () => normalizeAiStateTreeAsset({ schema: 1, type: "stateTree", context: { fn: () => null }, states: [{ id: "A" }] }),
    /stateTree\.context\.fn must be JSON-serializable/,
  );
});

