check("forge.moveAlongPatrolRoute approaches the nearest spline point before following look-ahead targets", () => {
  const actor = createDefaultSplineActor();
  actor.id = "patrol-rail";
  actor.spline.points[0]!.position = [0, 0, 0];
  actor.spline.points[1]!.position = [10, 0, 0];
  const registry = createSplineRegistry([actor]);
  const controller = new AIController("ai:guard", "guard", new Blackboard(), {
    patrolRoute: {
      source: "spline",
      splineId: "patrol-rail",
      entry: "nearest",
      speed: 2.4,
      acceptanceRadius: 0.55,
      lookAheadDistance: 1.5,
      wrapMode: "loop",
    },
  });
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: { kind: "task", task: "forge.moveAlongPatrolRoute" },
  });
  const requests: Array<{ position: [number, number, number]; preferredDirection?: [number, number, number]; preserveLocomotionOnSuccess?: boolean; speed?: number; acceptanceRadius?: number }> = [];
  let result: "running" | "success" = "running";
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: createDefaultAiTaskRegistry(),
    splineRegistry: registry,
    world: { entityPosition: () => [4, 0, 3] },
    moveTo: (request) => {
      requests.push({
        position: [request.position[0], request.position[1], request.position[2]],
        ...(request.preferredDirection
          ? { preferredDirection: [request.preferredDirection[0], request.preferredDirection[1], request.preferredDirection[2]] as [number, number, number] }
          : {}),
        ...(request.preserveLocomotionOnSuccess === true ? { preserveLocomotionOnSuccess: true } : {}),
        ...(request.speed !== undefined ? { speed: request.speed } : {}),
        ...(request.acceptanceRadius !== undefined ? { acceptanceRadius: request.acceptanceRadius } : {}),
      });
      return result;
    },
  });
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 }), "running");
  assert.ok(Math.abs((requests[0]?.position[0] ?? 0) - 4) < 1e-8);
  assert.ok((requests[0]?.preferredDirection?.[0] ?? 0) > 0.99, "spline tangent is forwarded");
  assert.equal(requests[0]?.preserveLocomotionOnSuccess, true);
  assert.deepEqual({ speed: requests[0]?.speed, acceptanceRadius: requests[0]?.acceptanceRadius }, {
    speed: 2.4,
    acceptanceRadius: 0.55,
  });
  result = "success";
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 }), "running");
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.048, frame: 3 }), "running");
  assert.ok(Math.abs((requests[2]?.position[0] ?? 0) - 5.5) < 1e-8);
  assert.deepEqual({ speed: requests[2]?.speed, acceptanceRadius: requests[2]?.acceptanceRadius }, {
    speed: 2.4,
    acceptanceRadius: 0.55,
  });
});

check("AI spline patrol move speed stays stable at 30 and 120 FPS through CharacterMovement", () => {
  const runForOneSecond = (fps: number): { positionX: number; planarSpeed: number | undefined } => {
    const actions = new ActionMap({});
    const entity: Entity = {
      id: "guard",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        CharacterMovement: {
          maxWalkSpeed: 4,
          sprintMultiplier: 1,
          jumpSpeed: 5,
          gravityScale: 1,
          orientRotationToMovement: true,
        },
      },
    };
    const splineLookAheadMove = { position: [100, 0, 0] as Vec3, speed: 2.4 };
    let lastReport: LocomotionInput | undefined;
    const movement = new CharacterMovementSubsystem(actions, () => undefined, undefined, {
      isPlayerControlled: () => false,
      getMoveIntent: (_entityId, transform) => ({
        direction: [
          splineLookAheadMove.position[0] - transform.position[0],
          splineLookAheadMove.position[2] - transform.position[2],
        ],
        speed: splineLookAheadMove.speed,
      }),
      reportLocomotion: (_entityId, report) => { lastReport = report; },
    });
    movement.setEntities([entity]);
    for (let frame = 1; frame <= fps; frame += 1) {
      movement.update({ deltaSeconds: 1 / fps, elapsedSeconds: frame / fps, frame });
    }
    return {
      positionX: movement.transformOf("guard")?.position[0] ?? 0,
      planarSpeed: lastReport?.planarSpeed,
    };
  };

  const thirtyFps = runForOneSecond(30);
  const oneTwentyFps = runForOneSecond(120);
  assert.ok(Math.abs(thirtyFps.positionX - 2.4) < 1e-8);
  assert.ok(Math.abs(oneTwentyFps.positionX - 2.4) < 1e-8);
  assert.equal(thirtyFps.planarSpeed, 2.4);
  assert.equal(oneTwentyFps.planarSpeed, 2.4);
});

check("AI spline patrol wrap modes advance deterministically at route boundaries", () => {
  assert.deepEqual(advanceSplinePatrolDistance(9, 1, 3, 10, "loop"), {
    distance: 2,
    direction: 1,
    atBoundary: false,
  });
  assert.deepEqual(advanceSplinePatrolDistance(9, 1, 3, 10, "pingPong"), {
    distance: 8,
    direction: -1,
    atBoundary: false,
  });
  assert.deepEqual(advanceSplinePatrolDistance(9, 1, 3, 10, "clamp"), {
    distance: 10,
    direction: 1,
    atBoundary: true,
  });

  const rail = createDefaultSplineActor();
  rail.id = "closed-patrol-rail";
  const [firstPoint, secondPoint] = rail.spline.points;
  assert.ok(firstPoint && secondPoint);
  rail.spline.points = [
    { ...firstPoint, position: [0, 0, 0] },
    { ...secondPoint, position: [10, 0, 0] },
    { ...secondPoint, id: "closed-patrol-point-3", position: [10, 0, 10] },
    { ...secondPoint, id: "closed-patrol-point-4", position: [0, 0, 10] },
  ];
  rail.spline.closed = true;
  const query = createSplineRegistry([rail]).getSplineById(rail.id);
  assert.ok(query);
  const length = query.getLength();
  const before = query.getLocationAtDistance(length - 0.01, "world");
  const afterDistance = advanceSplinePatrolDistance(length - 0.01, 1, 0.02, length, "loop").distance;
  const after = query.getLocationAtDistance(afterDistance, "world");
  assert.ok(Math.hypot(before[0] - after[0], before[1] - after[1], before[2] - after[2]) < 0.03,
    "closed-loop seam must remain spatially continuous");
});

