check("AI save payloads enforce compound extensions, traversal guard, and normalizers", () => {
  const blackboard = { schema: 1, type: "blackboard", keys: [{ key: "target", kind: "entity" }] };
  const behavior = {
    schema: 1,
    type: "behaviorTree",
    root: { kind: "task", task: "forge.wait" },
  };
  assert.equal(
    validateSaveAiBlackboardPayload({
      path: "assets/AI/Enemy.blackboard.json",
      blackboard,
    }).blackboard.type,
    "blackboard",
  );
  assert.equal(
    validateSaveAiBehaviorPayload({
      path: "assets/AI/Enemy.behavior.json",
      behavior,
    }).behavior.type,
    "behaviorTree",
  );
  assert.equal(
    validateSaveAiQueryPayload({
      path: "assets/AI/BestCover.query.json",
      query: { schema: 1, type: "query", generators: [{ kind: "actorsByTag", tag: "cover" }] },
    }).query.type,
    "query",
  );
  assert.equal(
    validateSaveAiStateTreePayload({
      path: "assets/AI/Enemy.stateTree.json",
      stateTree: { schema: 1, type: "stateTree", states: [{ id: "Idle" }] },
    }).stateTree.type,
    "stateTree",
  );
  assert.throws(
    () =>
      validateSaveAiStateTreePayload({
        path: "assets/AI/Enemy.json",
        stateTree: { schema: 1, type: "stateTree", states: [{ id: "Idle" }] },
      }),
    /\.stateTree\.json/,
  );
  assert.throws(
    () => validateSaveAiBlackboardPayload({ path: "assets/AI/Enemy.json", blackboard }),
    /\.blackboard\.json/,
  );
  assert.throws(
    () => validateSaveAiBehaviorPayload({ path: "../Enemy.behavior.json", behavior }),
    /must not contain \.\./,
  );
  assert.throws(
    () => validateSaveAiQueryPayload({ path: "assets/AI/BestCover.json", query: {} }),
    /\.query\.json/,
  );
});

