check("AI perception sight respects radius, horizontal FOV, and blocker LOS", () => {
  const listener = {
    entityId: "enemy",
    position: [0, 0, 0] as [number, number, number],
    forward: [0, 0, 1] as [number, number, number],
    sightRadius: 6,
    fieldOfViewDeg: 90,
  };
  assert.equal(insideHorizontalFov(listener.position, listener.forward, [0, 0, 4], 90), true);
  assert.equal(insideHorizontalFov(listener.position, listener.forward, [4, 0, 0], 90), false);
  assert.deepEqual(
    evaluateSight(listener, [
      { entityId: "front", position: [0, 0, 4] },
      { entityId: "side", position: [4, 0, 0] },
      { entityId: "far", position: [0, 0, 8] },
    ]).map((stimulus) => stimulus.sourceEntityId),
    ["front"],
  );
  const wall = { min: [-1, -1, 2], max: [1, 2, 2.2] };
  assert.equal(segmentIntersectsAabb([0, 0, 0], [0, 0, 4], wall), true);
  assert.equal(
    evaluateSight(listener, [{ entityId: "front", position: [0, 0, 4] }], [wall]).length,
    0,
  );
  assert.deepEqual(
    evaluateSight(
      { ...listener, nearSightRadius: 1 },
      [{ entityId: "near-blocked", position: [0, 0, 0.8] }],
      [{ min: [-1, -1, 0.3], max: [1, 2, 0.4] }],
    ).map((stimulus) => stimulus.sourceEntityId),
    ["near-blocked"],
  );
});

check("AI perception hearing applies loudness-scaled radius", () => {
  const listener = {
    entityId: "enemy",
    position: [0, 0, 0] as [number, number, number],
    forward: [0, 0, 1] as [number, number, number],
    hearingRadius: 5,
  };
  const heard = evaluateHearing(listener, [
    { sourceEntityId: "step", position: [3, 0, 0], loudness: 1 },
    { sourceEntityId: "quiet", position: [6, 0, 0], loudness: 1 },
    { sourceEntityId: "loud", position: [8, 0, 0], loudness: 2 },
  ]);
  assert.deepEqual(heard.map((stimulus) => stimulus.sourceEntityId), ["step", "loud"]);
  assert.equal(heard[0]?.sense, "hearing");
  assert.ok((heard[0]?.strength ?? 0) > (heard[1]?.strength ?? 0));
});

check("AI perception dominant stimulus uses sense priority before strength", () => {
  const dominant = dominantPerceivedStimulus([
    {
      sense: "hearing",
      sourceEntityId: "loud-noise",
      position: [1, 0, 0],
      distance: 1,
      strength: 0.95,
    },
    {
      sense: "damage",
      sourceEntityId: "attacker",
      position: [6, 0, 0],
      distance: 6,
      strength: 0.2,
      eventType: "Damage.Apply",
    },
  ]);
  assert.equal(dominant?.sense, "damage");
  assert.equal(dominant?.sourceEntityId, "attacker");

  const sameSense = dominantPerceivedStimulus([
    {
      sense: "hearing",
      sourceEntityId: "near-quiet",
      position: [1, 0, 0],
      distance: 1,
      strength: 0.4,
    },
    {
      sense: "hearing",
      sourceEntityId: "far-loud",
      position: [4, 0, 0],
      distance: 4,
      strength: 0.8,
    },
  ]);
  assert.equal(sameSense?.sourceEntityId, "far-loud");
});

check("AISubsystem derives one controller per AIController entity, ticks safely, and gates", () => {
  const ai = new AISubsystem();
  ai.setEntities([
    {
      id: "enemy-1",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [AI_CONTROLLER_COMPONENT]: {
          behaviorTree: "assets/AI/Enemy.behavior.json",
          blackboardKeys: [{ key: "target", kind: "entity", default: null }],
        },
      },
    },
    { id: "prop-1", components: {} },
  ]);
  assert.equal(ai.controllerCount(), 1);
  const controller = ai.getControllerForPawn("enemy-1");
  assert.ok(controller);
  assert.equal(controller?.pawnEntityId, "enemy-1");
  assert.equal(controller?.blackboard.keyCount(), 1);
  assert.equal(controller?.behaviorTreeAsset, "assets/AI/Enemy.behavior.json");
  assert.equal(ai.getControllerForPawn("prop-1"), undefined);

  const snap = ai.getDebugSnapshot();
  assert.equal(snap.enabled, true);
  assert.equal(snap.controllerCount, 1);
  assert.equal(snap.controllers[0]?.pawnEntityId, "enemy-1");
  assert.equal(snap.controllers[0]?.blackboard.keyCount, 1);

  // Runtime smoke: ticking (enabled and gated off) must not throw and must leave
  // the controller set intact.
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  ai.setEnabled(false);
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 });
  assert.equal(ai.isEnabled(), false);
  assert.equal(ai.getDebugSnapshot().enabled, false);
  assert.equal(ai.controllerCount(), 1);

  // A rebuild with an empty set clears controllers (scene teardown/reload).
  ai.setEntities([]);
  assert.equal(ai.controllerCount(), 0);
});

check("AISubsystem runs a StateTree when the AIController references a stateTree asset", () => {
  const ai = new AISubsystem();
  ai.setAssetLibrary({
    blackboards: new Map([
      [
        "assets/AI/Guard.blackboard.json",
        normalizeAiBlackboardAsset({
          schema: 1,
          type: "blackboard",
          keys: [
            { key: "mode", kind: "string", default: null },
            { key: "alarm", kind: "boolean", default: false },
          ],
        }),
      ],
    ]),
    stateTrees: new Map([
      [
        "assets/AI/Guard.stateTree.json",
        normalizeAiStateTreeAsset({
          schema: 1,
          type: "stateTree",
          blackboard: "assets/AI/Guard.blackboard.json",
          states: [
            {
              id: "Idle",
              tasks: [{ task: "forge.setBlackboard", params: { key: "mode", value: "idle" } }],
              transitions: [
                { to: "Alert", conditions: [{ kind: "blackboard", key: "alarm", op: "equals", value: true }] },
              ],
            },
            {
              id: "Alert",
              tasks: [{ task: "forge.setBlackboard", params: { key: "mode", value: "alert" } }],
            },
          ],
        }),
      ],
    ]),
  });
  ai.setEntities([
    {
      id: "guard",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        // Both authored: the StateTree must win over the Behavior Tree.
        [AI_CONTROLLER_COMPONENT]: {
          stateTree: "assets/AI/Guard.stateTree.json",
          behaviorTree: "assets/AI/Missing.behavior.json",
        },
      },
    },
  ]);
  const controller = ai.getControllerForPawn("guard");
  assert.ok(controller);
  // Blackboard resolved from the StateTree asset's blackboard reference.
  assert.equal(controller?.blackboard.keyCount(), 2);
  assert.equal(controller?.stateTreeAsset, "assets/AI/Guard.stateTree.json");

  ai.update({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 1 });
  assert.equal(controller?.goal, "Idle");
  assert.equal(controller?.blackboard.getString("mode"), "idle");

  const idleSnap = ai.getDebugSnapshot().controllers[0];
  assert.ok(idleSnap?.stateTree, "StateTree runner debug should be present");
  assert.equal(idleSnap?.behavior, null);
  assert.equal(idleSnap?.stateTreeAsset, "assets/AI/Guard.stateTree.json");
  assert.deepEqual(idleSnap?.stateTree?.activePath, ["Idle"]);

  // Guard condition flips the active state, driven through the shared task registry.
  controller?.blackboard.set("alarm", true);
  ai.update({ deltaSeconds: 0.1, elapsedSeconds: 0.2, frame: 2 });
  assert.equal(controller?.goal, "Alert");
  assert.equal(controller?.blackboard.getString("mode"), "alert");
  const alertSnap = ai.getDebugSnapshot().controllers[0];
  assert.deepEqual(alertSnap?.stateTree?.activePath, ["Alert"]);
  assert.equal(alertSnap?.stateTree?.lastTransition?.to, "Alert");
});

check("AISubsystem derives perception listeners from AIController props and consumes noise events", () => {
  const wall = { min: [-1, -1, 2], max: [1, 2, 2.2] };
  const ai = new AISubsystem({ blockers: () => [wall] });
  ai.setEntities([
    {
      id: "enemy",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [AI_CONTROLLER_COMPONENT]: {
          perception: { sightRadius: 6, fieldOfViewDeg: 90, hearingRadius: 5 },
        },
      },
    },
    {
      id: "target",
      components: {
        Transform: { position: [0, 0, 4], rotation: [0, 0, 0], scale: [1, 1, 1] },
      },
    },
  ]);
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  assert.equal(ai.getDebugSnapshot().controllers[0]?.perception?.length, 0, "wall blocks sight");
  ai.emitNoise([0, 0, 4], "target");
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 });
  const perceived = ai.getDebugSnapshot().controllers[0]?.perception ?? [];
  assert.equal(perceived[0]?.sense, "hearing");
  assert.equal(perceived[0]?.sourceEntityId, "target");
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.048, frame: 3 });
  assert.equal(ai.getDebugSnapshot().controllers[0]?.perception?.length, 0, "noise is transient");
});

