// --- Editor↔game DI seam (gameEditorRegistry) --------------------------------
// Guards the inversion that keeps the editor generic: the editor reads game data
// through the injected catalog, never importing @/game. The throw-before-inject
// check must run before the register call below (module-singleton state).

check("gameEditorRegistry throws until the composition root injects a catalog", () => {
  assert.throws(() => getGameEditorCatalog(), /was not registered/);
});

check("GAME_EDITOR_CATALOG satisfies the editor catalog contract once injected", () => {
  setGameEditorCatalog(GAME_EDITOR_CATALOG);
  const catalog = getGameEditorCatalog();
  // Game Modes: the default camera mode leads the World Settings dropdown.
  assert.ok(catalog.gameModeOptions.length >= 1);
  assert.equal(catalog.gameModeOptions[0]?.id, "forge.defaultCamera");
  // Behavior ids offered as Event Binding suggestions.
  assert.ok(catalog.behaviorScriptIds.includes("input-move"));
  // Input helpers resolve real bindings for the Actor Script montage→input panel.
  assert.equal(catalog.formatInputCode("KeyQ"), "Q");
  assert.ok(catalog.keysForAction("jump").includes("Space"));
  // Montage resolver is pure and safe on empty/absent input.
  assert.deepEqual(catalog.resolveMontageBindings(undefined), []);
  assert.deepEqual(catalog.resolveMontageBindings([]), []);

  // Data Table editor: the units balance is registered as an editable table, and
  // its `validate` is the real runtime validator wrapped — null for the shipped
  // file, a field message for a broken edit. This is what stops the editor from
  // ever writing balance the `?rts` boot would reject.
  const unitsTable = catalog.dataTables?.find((table) => table.id === "units")
    ?? assert.fail("units data table is not registered in the editor catalog");
  assert.equal(unitsTable.path, "game-data/balance/units.json");
  const realUnits = JSON.parse(readFileSync("public/game-data/balance/units.json", "utf8")) as unknown;
  assert.equal(unitsTable.validate(realUnits), null, "the shipped units file validates");
  const broken = JSON.parse(JSON.stringify(realUnits)) as Record<string, any>;
  broken.guard_placeholder.maxHealth = -5;
  assert.equal(
    typeof unitsTable.validate(broken),
    "string",
    "an out-of-range edit is refused with a field message, not accepted",
  );

  // Every registered table is wired to the right validator for its own file: the
  // shipped file must validate, which catches a copy-paste that pairs (say) the
  // buildings path with the units validator.
  for (const table of catalog.dataTables ?? []) {
    assert.match(table.path, /^game-data\/balance\/[a-z]+\.json$/, `${table.id} path is a balance file`);
    const real = JSON.parse(readFileSync(`public/${table.path}`, "utf8")) as unknown;
    assert.equal(table.validate(real), null, `the shipped ${table.id} file validates through its registered validator`);
  }
});

check("validateSaveGameDataPayload fences writes to game-data JSON and rejects the rest", () => {
  // The dev endpoint's guard is generic on purpose: path scope + a keyed object,
  // no balance rules (those ride on the injected validator above and the runtime
  // loader). Accepts a real balance path; refuses escapes and non-objects.
  const ok = validateSaveGameDataPayload({ path: "game-data/balance/units.json", data: { a: {} } });
  assert.equal(ok.path, "game-data/balance/units.json");
  assert.deepEqual(ok.data, { a: {} });
  // A leading slash is normalised rather than rejected.
  assert.equal(
    validateSaveGameDataPayload({ path: "/game-data/balance/units.json", data: {} }).path,
    "game-data/balance/units.json",
  );
  for (const bad of [
    { path: "src/main.ts", data: {} },
    { path: "game-data/../secret.json", data: {} },
    { path: "game-data/balance/units.json", data: [] },
    { path: "game-data/balance/units.json", data: "x" },
    { path: 42, data: {} },
    null,
  ]) {
    assert.throws(() => validateSaveGameDataPayload(bad), /gameData payload/);
  }
});

// Runtime `?debug` snapshot builders (P2.5): pure, side-effect-free, so the
// null-branching + default-fallback logic is exercised without a live scene.
check("buildPerfMemorySnapshot passes render memory through and reads the JS heap", () => {
  const render = { geometries: 3, textures: 4, programs: 2 } as unknown as Parameters<
    typeof buildPerfMemorySnapshot
  >[0];
  const snapshot = buildPerfMemorySnapshot(render);
  assert.equal(snapshot.render, render);
  // performance.memory is Chrome-only; under node it is absent → null heap fields.
  const hasPerfMemory =
    typeof performance !== "undefined" &&
    typeof (performance as { memory?: unknown }).memory !== "undefined";
  if (!hasPerfMemory) {
    assert.equal(snapshot.jsHeapBytes, null);
    assert.equal(snapshot.jsHeapLimitBytes, null);
  }
});

