check("RTS single-click selects one unit and double-click selects every matching role", () => {
  const units = new UnitSystem();
  const guards = [
    units.spawn("player", -3, 0, RTS_TEST_UNIT_STATS),
    units.spawn("player", -1, 0, RTS_TEST_UNIT_STATS),
  ];
  const archers = [
    units.spawn("player", 1, 0, RTS_TEST_ARCHER_STATS),
    units.spawn("player", 3, 0, RTS_TEST_ARCHER_STATS),
  ];
  const rams = [
    units.spawn("player", -2, -4, RTS_TEST_SIEGE_STATS),
    units.spawn("player", 2, -4, RTS_TEST_SIEGE_STATS),
  ];
  const workers = [
    units.spawn("player", -2, 4, RTS_TEST_WORKER_STATS),
    units.spawn("player", 2, 4, RTS_TEST_WORKER_STATS),
  ];
  units.spawn("enemy", -5, 0, RTS_TEST_UNIT_STATS);
  units.root.updateMatrixWorld(true);

  const camera = new PerspectiveCamera(60, 1, 0.1, 100);
  camera.position.set(0, 12, 14);
  camera.lookAt(0, 0, 0);
  camera.updateMatrixWorld(true);
  const canvas = { clientWidth: 100, clientHeight: 100 } as HTMLCanvasElement;
  const marquee = { show: () => {}, hide: () => {} } as unknown as MarqueeOverlay;
  const selection = new SelectionSystem(canvas, camera, units, marquee);
  const screenPointFor = (unit: Unit) => {
    const projected = new Vector3(unit.position.x, 1, unit.position.z).project(camera);
    return { x: (projected.x * 0.5 + 0.5) * 100, y: (-projected.y * 0.5 + 0.5) * 100 };
  };

  for (const group of [guards, archers, rams]) {
    const point = screenPointFor(group[0]!);
    selection.onSelectDoubleClick(point.x, point.y, false);
    assert.deepEqual(new Set(selection.selected()), new Set(group));
  }

  const workerPoint = screenPointFor(workers[0]!);
  selection.onSelectClick(workerPoint.x, workerPoint.y, false);
  assert.deepEqual(new Set(selection.selected()), new Set([workers[0]]), "a worker click selects only that worker");
  selection.onSelectDoubleClick(workerPoint.x, workerPoint.y, false);
  assert.deepEqual(new Set(selection.selected()), new Set(workers), "a worker double-click selects the whole worker line");
});

check("RTS health clamps damage and healing while exposing current/max/ratio", () => {
  const health = new HealthComponent(100);
  assert.equal(health.current, 100);
  assert.equal(health.max, 100);
  assert.equal(health.ratio, 1);
  assert.equal(health.depleted, false);

  const hit = health.damage(35);
  assert.deepEqual(hit, { applied: 35, previous: 100, current: 65, depleted: false });
  assert.equal(health.ratio, 0.65);

  const lethal = health.damage(100);
  assert.deepEqual(lethal, { applied: 65, previous: 65, current: 0, depleted: true });
  assert.equal(health.depleted, true);

  const healed = health.heal(200);
  assert.deepEqual(healed, { applied: 100, previous: 0, current: 100, depleted: false });
  assert.throws(() => health.damage(-1), RangeError);
  assert.throws(() => new HealthComponent(0), RangeError);

  // upgradeMax carries current health up by the *delta*, so the damage already
  // taken is preserved as an absolute figure (30 down before, 30 down after);
  // setMax may lower and clamps instead. Raising the ceiling alone would make an
  // undamaged 700/700 building read as 700/1000 — see health.ts.
  health.damage(30);
  health.upgradeMax(160);
  assert.deepEqual([health.current, health.max], [130, 160], "a raised ceiling keeps the damage already taken, not the ratio");
  assert.throws(() => health.upgradeMax(150), RangeError, "upgradeMax refuses to lower the maximum");
  health.setMax(50);
  assert.deepEqual([health.current, health.max], [50, 50], "setMax lowers the ceiling and clamps current into range");
  health.setMax(120);
  assert.deepEqual([health.current, health.max], [50, 120], "raising the ceiling again does not heal");
  assert.throws(() => health.setMax(0), RangeError);
});

check("unit balance validates combat stats for stable unit ids", () => {
  const balance = validateUnitBalance(
    JSON.parse(readFileSync("public/game-data/balance/units.json", "utf8")) as unknown,
  );
  // The roster contract, not the tuning: asserting concrete health/damage here
  // would make every balance pass a test failure (plan §75).
  assert.deepEqual(
    Object.keys(balance).sort(),
    ["archer_placeholder", "guard_placeholder", "siege_placeholder", "worker_placeholder"],
    "Faz 7 ships the Guard/Archer/Siege core roster plus the worker",
  );
  assert.equal(balance["guard_placeholder"]?.role, "guard");
  assert.equal(balance["archer_placeholder"]?.attackType, "ranged");
  assert.equal(balance["siege_placeholder"]?.role, "siege");
  assert.deepEqual(balance["worker_placeholder"]?.cost, { food: 50 });

  // The Archer opens from a Town-age Range; only the Ram needs Barracks II.
  assert.equal(balance["guard_placeholder"]?.requiredBuildingLevel, 1);
  assert.equal(balance["archer_placeholder"]?.requiredBuildingLevel, 1);
  assert.equal(balance["siege_placeholder"]?.requiredBuildingLevel, 2);
  assert.equal(balance["archer_placeholder"]?.productionBuildingId, "archery_range");
  assert.equal(balance["archer_placeholder"]?.requiredAge, "town");

  for (const [id, stats] of Object.entries(balance)) {
    if (id === "worker_placeholder") continue;
    assert.ok(stats.moveSpeed > 0, `${id} carries a data-owned move speed`);
    assert.ok(stats.acquisitionRange > 0, `${id} can find its own targets`);
  }
  // GDD 12 §33 read as a contract rather than as numbers: each role's identity
  // is which column it is best against, and that must hold after any retune.
  const bestClass = (id: string) =>
    (Object.entries(balance[id]!.damageMultipliers) as [string, number][])
      .sort((left, right) => right[1] - left[1])[0]![0];
  assert.equal(bestClass("guard_placeholder"), "heavy", "the Guard is the front-line answer to other heavies");
  assert.equal(bestClass("archer_placeholder"), "light", "the Archer punishes light units");
  assert.equal(bestClass("siege_placeholder"), "structure", "siege exists to break buildings");
  assert.ok(
    balance["siege_placeholder"]!.damageMultipliers.structure
      > balance["guard_placeholder"]!.damageMultipliers.structure * 4,
    "plan §46: siege is *necessary* against buildings, not merely better",
  );
  assert.ok(
    balance["archer_placeholder"]!.attackRange > balance["guard_placeholder"]!.attackRange * 3,
    "plan §46: the Archer is only effective while it is not reached",
  );

  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, maxHealth: 0 } }),
    GameDataError,
  );
  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, attackCooldown: 0 } }),
    GameDataError,
  );
  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, trainingSeconds: 0 } }),
    GameDataError,
  );
  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, moveSpeed: 0 } }),
    GameDataError,
    "a motionless unit is a data bug, not a design",
  );
  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, role: "cavalry" } }),
    GameDataError,
    "cavalry is out of vertical-slice scope; the id must not slip in through data",
  );
  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, armorClass: "structure" } }),
    GameDataError,
    "only buildings carry the structure armour class",
  );
  assert.throws(
    () => validateUnitBalance({
      guard_placeholder: { ...RTS_TEST_UNIT_STATS, damageMultipliers: { light: 1, heavy: 1 } },
    }),
    GameDataError,
    "an attacker missing a §33 column would silently resolve to NaN damage",
  );
  assert.throws(
    () => validateUnitBalance({
      guard_placeholder: { ...RTS_TEST_UNIT_STATS, damageMultipliers: { light: 1, heavy: 1, structure: 0 } },
    }),
    GameDataError,
    "§33 counters are soft: a zero multiplier makes a matchup unwinnable",
  );
  assert.throws(
    () => validateUnitBalance({ guard_placeholder: { ...RTS_TEST_UNIT_STATS, chaseRange: 1 } }),
    GameDataError,
    "a leash shorter than acquisition would drop a target on the tick it was found",
  );
  assert.throws(
    () => validateUnitBalance({ archer_placeholder: { ...RTS_TEST_ARCHER_STATS, acquisitionRange: 2 } }),
    GameDataError,
    "a unit that sees less far than it shoots could never open fire",
  );
  assert.throws(() => validateUnitBalance({ "Guard Placeholder": RTS_TEST_UNIT_STATS }), GameDataError);
});

