check("RTS road graph finds obstacle-free cells, charges new segments, and keeps alternate connectivity", () => {
  const balance = validateRoadBalance(
    JSON.parse(readFileSync("public/game-data/balance/roads.json", "utf8")) as unknown,
  );
  assert.deepEqual(balance, { cellSize: 2, woodCostPerCell: 4 });
  const roads = new RoadGraph(balance);
  const blockers = [{ min: [-1, -1, -1], max: [1, 3, 1] }];
  const detour = roads.plan({ x: -6, z: 0 }, { x: 6, z: 0 }, blockers);
  assert.ok(detour, "road graph finds a flank around a blocked cell");
  assert.ok(detour.cells.every((cell) => cell.x !== 0 || cell.z !== 0), "route avoids the occupied road cell");
  assert.equal(detour.woodCost, detour.newCells.length * 4);
  roads.commit(detour);
  assert.equal(roads.connected({ x: -6, z: 0 }, { x: 6, z: 0 }), true);
  assert.ok(roads.all().some((segment) => segment.kind === "corner"), "detour produces corner segments");
  const corner = roads.all().find((segment) => segment.kind === "corner");
  assert.deepEqual(corner?.connections.length, 2, "a visual corner has exactly two exits");
  assert.ok(corner?.connections.some((direction) => direction === "north" || direction === "south"));
  assert.ok(corner?.connections.some((direction) => direction === "east" || direction === "west"));
  assert.equal(roads.components().length, 1);
  assert.equal(roads.edgeCount(), roads.all().length - 1, "the detour is one acyclic component");

  const isolated = roads.plan({ x: 30, z: 30 }, { x: 34, z: 30 }, blockers);
  assert.ok(isolated);
  roads.commit(isolated);
  assert.equal(roads.components().length, 2, "disconnected roads remain separate graph components");
  assert.equal(roads.version, 2);

  const overlap = roads.plan({ x: -6, z: 0 }, { x: 6, z: 0 }, blockers);
  assert.ok(overlap);
  assert.equal(overlap.woodCost, 0, "existing road cells are never charged twice");

  const redundant = new RoadGraph(balance);
  for (const [start, end] of [
    [{ x: -4, z: 0 }, { x: 4, z: 0 }],
    [{ x: -4, z: 0 }, { x: -4, z: 4 }],
    [{ x: -4, z: 4 }, { x: 4, z: 4 }],
    [{ x: 4, z: 4 }, { x: 4, z: 0 }],
  ] as const) {
    const plan = redundant.plan(start, end, []);
    assert.ok(plan);
    redundant.commit(plan);
  }
  assert.equal(redundant.remove([{ x: 0, z: 0 }]), 1);
  assert.equal(redundant.connected({ x: -4, z: 0 }, { x: 4, z: 0 }), true, "an alternate branch preserves connectivity after a road cut");
});

check("RTS depot age and level tiers provide four-resource global storage capacity", () => {
  const buildings = validateBuildingBalance(
    JSON.parse(readFileSync("public/game-data/balance/buildings.json", "utf8")) as unknown,
  );
  const depotStats = buildings.depot ?? assert.fail("depot definition missing");
  assert.deepEqual(depotStats.progression?.settlement.map((tier) => tier.storageCapacity), [
    { food: 500, wood: 500, stone: 300, gold: 300 },
    { food: 750, wood: 750, stone: 450, gold: 450 },
    { food: 1000, wood: 1000, stone: 600, gold: 600 },
  ]);
  assert.deepEqual(depotStats.progression?.town.map((tier) => tier.storageCapacity), [
    { food: 1400, wood: 1400, stone: 900, gold: 900 },
    { food: 1800, wood: 1800, stone: 1200, gold: 1200 },
    { food: 2400, wood: 2400, stone: 1600, gold: 1600 },
  ]);

  const units = new UnitSystem();
  const structures = new PlacedStructureSystem();
  const kingdoms = new KingdomRegistry(["player"], units, structures, { wood: 1000, stone: 1000 }, 20);
  let age: "settlement" | "town" = "settlement";
  const upgrades = new StructureUpgradeSystem(structures, kingdoms, () => age);
  const capacity = new ResourceCapacitySystem(structures);
  const depot = structures.place("player", depotStats, 0, 0);
  structures.advanceConstruction(depot, depotStats.constructionSeconds);
  assert.equal(upgrades.applyCompletedUpgrade(depot), true);
  assert.deepEqual(depot.storageCapacity, { food: 500, wood: 500, stone: 300, gold: 300 });
  assert.deepEqual(capacity.capacityFor("player"), { food: 1000, wood: 1000, stone: 600, gold: 600 });

  assert.equal(upgrades.start(depot), "started");
  upgrades.update(45);
  assert.deepEqual(depot.storageCapacity, { food: 750, wood: 750, stone: 450, gold: 450 });
  assert.deepEqual(capacity.capacityFor("player"), { food: 1250, wood: 1250, stone: 750, gold: 750 });

  age = "town";
  upgrades.resetOwner("player");
  assert.deepEqual(depot.storageCapacity, { food: 1400, wood: 1400, stone: 900, gold: 900 });
  assert.equal(capacity.availableFor("player", "food", 1900), 0, "a full global store refuses further delivery");
  assert.equal(capacity.availableFor("player", "food", 1850), 50);
  structures.clear();
});

check("RTS full storage leaves linked production in its local buffer until capacity is freed", () => {
  const buildings = validateBuildingBalance(
    JSON.parse(readFileSync("public/game-data/balance/buildings.json", "utf8")) as unknown,
  );
  const roadBalance = validateRoadBalance(
    JSON.parse(readFileSync("public/game-data/balance/roads.json", "utf8")) as unknown,
  );
  const depotStats = buildings.depot ?? assert.fail("depot definition missing");
  const farmStats = buildings.farm ?? assert.fail("farm definition missing");
  const units = new UnitSystem();
  for (let index = 0; index < 3; index += 1) units.spawn("player", -2 + index * 2, 17, RTS_TEST_WORKER_STATS);
  const structures = new PlacedStructureSystem();
  const depot = structures.place("player", depotStats, 0, 0);
  const farm = structures.place("player", farmStats, 0, 10);
  structures.advanceConstruction(depot, depotStats.constructionSeconds);
  structures.advanceConstruction(farm, farmStats.constructionSeconds);
  depot.storageCapacity = depotStats.progression?.settlement[0]?.storageCapacity ?? null;
  const navigation = new RtsNavigation();
  navigation.setBlockers(structures.navigationBlockers());
  const production = new EconomyProductionSystem(units, structures, navigation, () => false);
  const roads = new RoadGraph(roadBalance);
  const route = roads.plan({ x: 4, z: 0 }, { x: 4, z: 10 }, []);
  assert.ok(route);
  roads.commit(route);
  const kingdoms = new KingdomRegistry(["player"], units, structures, { food: 999 }, 20);
  const transfers = new LogisticsTransferSystem(
    production,
    new ProductionLogisticsSystem(structures, roads, new DepotLogisticsSystem(structures, roads)),
    kingdoms,
    new ResourceCapacitySystem(structures),
  );
  for (let frame = 0; frame < 900; frame += 1) {
    updateUnitMovement(units.all(), 1 / 60);
    production.update(1 / 60);
    transfers.update();
  }
  assert.equal(kingdoms.get("player").wallet.amount("food"), 1000, "delivery stops at the depot-backed limit");
  assert.ok((production.snapshots("player")[0]?.localBuffer ?? 0) > 0, "excess output remains locally buffered");
  structures.clear();
  units.clear();
});

check("RTS completed depots become road-graph nodes only when a road touches their footprint", () => {
  const balance = validateRoadBalance(
    JSON.parse(readFileSync("public/game-data/balance/roads.json", "utf8")) as unknown,
  );
  const buildings = validateBuildingBalance(
    JSON.parse(readFileSync("public/game-data/balance/buildings.json", "utf8")) as unknown,
  );
  const depotStats = buildings.depot ?? assert.fail("depot definition missing");
  const structures = new PlacedStructureSystem();
  const depot = structures.place("player", depotStats, 0, 0);
  structures.advanceConstruction(depot, depotStats.constructionSeconds);
  const farmStats = buildings.farm ?? assert.fail("farm definition missing");
  const farm = structures.place("player", farmStats, 0, 10);
  structures.advanceConstruction(farm, farmStats.constructionSeconds);
  const roads = new RoadGraph(balance);
  const logistics = new DepotLogisticsSystem(structures, roads);
  const productionLogistics = new ProductionLogisticsSystem(structures, roads, logistics);
  assert.deepEqual(logistics.snapshots().map(({ status }) => status), ["unlinked"]);
  assert.deepEqual(productionLogistics.snapshots().map(({ status }) => status), ["unlinked-road"]);

  const route = roads.plan({ x: 4, z: 0 }, { x: 4, z: 8 }, []);
  assert.ok(route);
  roads.commit(route);
  assert.deepEqual(logistics.snapshots(), [{
    structureId: depot.id,
    owner: "player",
    x: 0,
    z: 0,
    roadCell: { x: 4, z: 0 },
    componentId: 1,
    status: "linked",
  }]);
  assert.deepEqual(productionLogistics.snapshots(), [{
    structureId: farm.id,
    owner: "player",
    resourceId: "food",
    roadCell: { x: 4, z: 6 },
    componentId: 1,
    depotStructureId: depot.id,
    status: "linked",
  }]);
  const occupation = new LogisticsOccupationSystem(logistics);
  occupation.setOccupier(depot.id, "enemy");
  const occupiedLink = new ProductionLogisticsSystem(structures, roads, logistics, undefined, occupation);
  assert.equal(occupiedLink.snapshots()[0]?.status, "depot-occupied");
  occupation.setOccupier(depot.id, null);
  const neutralTerritory = new TerritoryControlSystem(() => []);
  neutralTerritory.refresh();
  const outsideControl = new ProductionLogisticsSystem(structures, roads, logistics, neutralTerritory);
  assert.equal(outsideControl.snapshots()[0]?.status, "outside-control");
  neutralTerritory.dispose();
  structures.clear();
});

check("RTS logistics transfers linked buffers globally and stops when the road is cut", () => {
  const buildings = validateBuildingBalance(JSON.parse(readFileSync("public/game-data/balance/buildings.json", "utf8")) as unknown);
  const balance = validateRoadBalance(JSON.parse(readFileSync("public/game-data/balance/roads.json", "utf8")) as unknown);
  const farmStats = buildings.farm ?? assert.fail("farm definition missing");
  const depotStats = buildings.depot ?? assert.fail("depot definition missing");
  const units = new UnitSystem();
  for (let index = 0; index < 3; index += 1) units.spawn("player", -2 + index * 2, 17, RTS_TEST_WORKER_STATS);
  const structures = new PlacedStructureSystem();
  const depot = structures.place("player", depotStats, 0, 0);
  const farm = structures.place("player", farmStats, 0, 10);
  structures.advanceConstruction(depot, depotStats.constructionSeconds);
  structures.advanceConstruction(farm, farmStats.constructionSeconds);
  const navigation = new RtsNavigation();
  navigation.setBlockers(structures.navigationBlockers());
  const production = new EconomyProductionSystem(units, structures, navigation, () => false);
  const roads = new RoadGraph(balance);
  const depots = new DepotLogisticsSystem(structures, roads);
  const links = new ProductionLogisticsSystem(structures, roads, depots);
  const kingdoms = new KingdomRegistry(["player", "enemy"], units, structures, { food: 0, wood: 0 }, 20);
  const wallet = kingdoms.get("player").wallet;
  const transfer = new LogisticsTransferSystem(production, links, kingdoms);

  for (let frame = 0; frame < 900; frame += 1) {
    updateUnitMovement(units.all(), 1 / 60);
    production.update(1 / 60);
    transfer.update();
  }
  assert.equal(wallet.amount("food"), 0, "unlinked output remains local");
  assert.ok((production.snapshots()[0]?.localBuffer ?? 0) > 0);
  const route = roads.plan({ x: 4, z: 0 }, { x: 4, z: 10 }, []);
  assert.ok(route);
  roads.commit(route);
  for (let frame = 0; frame < 120; frame += 1) {
    wallet.advance(1 / 60);
    updateUnitMovement(units.all(), 1 / 60);
    production.update(1 / 60);
    transfer.update();
  }
  assert.ok(wallet.amount("food") > 0, "linked output reaches global stock");
  assert.equal(production.snapshots()[0]?.localBuffer, 0, "linked buffer flushes every tick");
  const beforeCut = wallet.amount("food");
  roads.clear();
  for (let frame = 0; frame < 120; frame += 1) {
    wallet.advance(1 / 60);
    production.update(1 / 60);
    transfer.update();
  }
  assert.equal(wallet.amount("food"), beforeCut, "road loss stops global credit");
  assert.ok((production.snapshots()[0]?.localBuffer ?? 0) > 0, "disconnected output returns to local storage");
  structures.clear();
  units.clear();
});

